// LatexLexerInit initializes any static state used to implement LatexLexer. By default the
// static state used to implement the lexer is lazily initialized during the first call to
// NewLatexLexer(). You can call this function if you wish to initialize the static state ahead
// of time.
func LatexLexerInit() {
  staticData := &LatexLexerLexerStaticData
  staticData.once.Do(latexlexerLexerInit)
}

// NewLatexLexer produces a new lexer instance for the optional input antlr.CharStream.
func NewLatexLexer(input antlr.CharStream) *LatexLexer {
  LatexLexerInit()
	l := new(LatexLexer)
	l.BaseLexer = antlr.NewBaseLexer(input)
  staticData := &LatexLexerLexerStaticData
	l.Interpreter = antlr.NewLexerATNSimulator(l, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	l.channelNames = staticData.ChannelNames
	l.modeNames = staticData.ModeNames
	l.RuleNames = staticData.RuleNames
	l.LiteralNames = staticData.LiteralNames
	l.SymbolicNames = staticData.SymbolicNames
	l.GrammarFileName = "Latex.g4"
	// TODO: l.EOF = antlr.TokenEOF

	return l
}

